const fs = require('fs');
const path = require('path');

const validFileTypes = [
  'org', 'md', 'markdown', 'txt', 'html', 'xml',
  'appleplist', 'asm', 'asp', 'batch', 'c', 'cs', 'css', 'csv', 'eml', 'go',
  'ini', 'internetshortcut', 'java', 'javascript', 'json', 'latex', 'lisp',
  'makefile', 'mht', 'mum', 'pem', 'perl', 'php', 'powershell', 'python',
  'rdf', 'rst', 'rtf', 'ruby', 'rust', 'scala', 'shell', 'smali', 'sql', 'svg',
  'symlinktext', 'vba', 'winregistry', 'yaml', 'pdf', 'jpg', 'jpeg', 'png', 'webp'
];

function isSupportedFileType(filePath) {
  const fileExtension = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(fileExtension);
}

function processDirectory(filesToPush, folderPath) {
  try {
    const files = fs.readdirSync(folderPath, { withFileTypes: true });
    for (const file of files) {
      const filePath = path.join(folderPath, file.name);
      if (file.name.startsWith('.')) continue;
      if (file.isFile() && isSupportedFileType(filePath)) {
        filesToPush.push(filePath);
      }
      if (file.isDirectory()) {
        processDirectory(filesToPush, filePath);
      }
    }
  } catch (err) {
    console.error(`Error reading directory ${folderPath}:`, err.message);
  }
}

return { filesToPush: [] };

const fs = require('fs');

const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const files = $input.all()[0].json.filesToPush || [];
const filesDataToPush = [];

for (const file of files) {
  try {
    if (!fs.existsSync(file)) continue;

    const stats = fs.statSync(file);
    const encoding = binaryFileTypes.includes(file.split('.').pop()) ? 'binary' : 'utf8';
    const content = fs.readFileSync(file, { encoding });

    filesDataToPush.push({
      path: file,
      content: content,
      encoding: encoding,
      mtime: stats.mtime.toISOString()
    });
  } catch (err) {
    console.error(`Error reading file ${file}:`, err.message);
  }
}

return { filesDataToPush };

const lastSync = $input.all()[0].json.filesDataToPush || [];

return {
  lastSync: lastSync.map(file => ({
    path: file.path,
    datetime: new Date().toISOString()
  }))
};

const error = $input.json;
let errorMessage = 'Sync was unsuccessful';

if (error.code === 'ECONNREFUSED') {
  errorMessage = `Could not connect to Khoj server at ${error.address}:${error.port}`;
} else if (error.status === 429) {
  errorMessage = 'Out of space. Upgrade your plan to unlock more space.';
} else {
  errorMessage = error.message || errorMessage;
}

return { error: true, errorMessage };
